@@ -0,0 +1,96 @@
+import express from "express";
+import http from "http";
+import { Server } from "socket.io";
+import cors from "cors";
+
+const app = express();
+app.use(cors());
+
+const server = http.createServer(app);
+const io = new Server(server, {
+  cors: {
+    origin: "http://localhost:5173",
+    methods: ["GET", "POST"],
+  },
+});
+
+// 🧠 In-memory store
+const rooms = ["general", "random", "tech", "fun", "study"];
+const roomUsers = {}; // { roomName: [ { id, username } ] }
+
+io.on("connection", (socket) => {
+  console.log("✅ User connected");
+
+  // Send available rooms to user
+  socket.emit("room-list", rooms);
+
+  // 👤 Join Room with Username
+  socket.on("join-room", ({ username, room }) => {
+    if (!roomUsers[room]) roomUsers[room] = [];
+
+    // ✅ Check duplicate usernames
+    const userExists = roomUsers[room].find((u) => u.username === username);
+    if (userExists) {
+      socket.emit("error-username", "Username already taken in this room.");
+      return;
+    }
+
+    // ✅ Save user data
+    socket.join(room);
+    socket.data.username = username;
+    socket.data.room = room;
+    roomUsers[room].push({ id: socket.id, username });
+
+    // Notify room
+    io.to(room).emit("user-list", roomUsers[room]);
+    io.to(room).emit("receive-message", {
+      sender: "System",
+      text: `${username} joined the room.`,
+      time: new Date().toLocaleTimeString(),
+    });
+
+    console.log(`🟢 ${username} joined room: ${room}`);
+  });
+
+  // 📨 Chat message
+  socket.on("send-message", ({ text }) => {
+    const msg = {
+      sender: socket.data.username,
+      text,
+      time: new Date().toLocaleTimeString(),
+    };
+    io.to(socket.data.room).emit("receive-message", msg);
+  });
+
+  // ➕ Create New Room
+  socket.on("create-room", (newRoom) => {
+    if (!rooms.includes(newRoom)) {
+      rooms.push(newRoom);
+      roomUsers[newRoom] = [];
+      io.emit("room-list", rooms);
+      console.log(`🆕 New room created: ${newRoom}`);
+    }
+  });
+
+  // ❌ User disconnects
+  socket.on("disconnect", () => {
+    const room = socket.data.room;
+    const username = socket.data.username;
+
+    if (room && roomUsers[room]) {
+      roomUsers[room] = roomUsers[room].filter((u) => u.id !== socket.id);
+      io.to(room).emit("user-list", roomUsers[room]);
+      io.to(room).emit("receive-message", {
+        sender: "System",
+        text: `${username} left the room.`,
+        time: new Date().toLocaleTimeString(),
+      });
+    }
+
+    console.log("❌ User disconnected");
+  });
+});
+
+server.listen(3000, () => {
+  console.log("🚀 Server running at http://localhost:3000");
+});

